1	import { defineStore } from 'pinia'
2	import { ref } from 'vue'
3	import type { ReceivingReceipt, PutawayTask, ReceiptStatus, Discrepancy } from '@/services/adapters/api-adapter.interface'
4	import { operationsApi } from './api'
5	import { normalizeError } from '@/utils/error-normalizer'
6	import type { ApiError } from '@/types/api'
7	
8	export const useOperationsStore = defineStore('operations', () => {
9	  const receipts = ref<ReceivingReceipt[]>([])
10	  const currentReceipt = ref<ReceivingReceipt | null>(null)
11	  const putawayTasks = ref<PutawayTask[]>([])
12	  const discrepancies = ref<Discrepancy[]>([])
13	  const loading = ref(false)
14	  const error = ref<ApiError | null>(null)
15	  const totalReceipts = ref(0)
16	
17	  const api = operationsApi()
18	
19	  async function fetchReceipts(page = 0, size = 25) {
20	    loading.value = true
21	    error.value = null
22	    try {
23	      const res = await api.getReceipts({ page, size })
24	      const payload = res.data as any
25	      if (Array.isArray(payload)) {
26	        receipts.value = payload
27	        totalReceipts.value = payload.length
28	      } else if (payload && Array.isArray(payload.content)) {
29	        receipts.value = payload.content
30	        totalReceipts.value = payload.totalElements ?? payload.content.length
31	      } else {
32	        receipts.value = []
33	        totalReceipts.value = 0
34	      }
35	    } catch (e) {
36	      error.value = normalizeError(e)
37	    } finally {
38	      loading.value = false
39	    }
40	  }
41	
42	  async function fetchReceipt(id: number) {
43	    loading.value = true
44	    error.value = null
45	    try {
46	      const res = await api.getReceipt(id)
47	      currentReceipt.value = res.data
48	    } catch (e) {
49	      error.value = normalizeError(e)
50	    } finally {
51	      loading.value = false
52	    }
53	  }
54	
55	  async function fetchDiscrepancies(receiptId: number) {
56	    try {
57	      const res = await api.getDiscrepancies(receiptId)
58	      const payload = res.data as any
59	      if (Array.isArray(payload)) {
60	        discrepancies.value = payload.map((d: any) => ({
61	          ...d,
62	          resolved: !!d.resolvedBy,
63	        }))
64	      } else {
65	        discrepancies.value = []
66	      }
67	    } catch (e) {
68	      discrepancies.value = []
69	    }
70	  }
71	
72	  async function createReceipt(data: { receiptType: string; referenceNumber?: string; supplierName?: string; expectedDate?: string }) {
73	    loading.value = true
74	    error.value = null
75	    try {
76	      const res = await api.createReceipt(data)
77	      return res.data
78	    } catch (e) {
79	      error.value = normalizeError(e)
80	      throw e
81	    } finally {
82	      loading.value = false
83	    }
84	  }
85	
86	  async function transitionReceipt(id: number, targetState: ReceiptStatus, reason?: string) {
87	    loading.value = true
88	    error.value = null
89	    try {
90	      await api.transitionReceipt(id, { targetState, reason })
91	      await fetchReceipt(id)
92	    } catch (e) {
93	      error.value = normalizeError(e)
94	      throw e
95	    } finally {
96	      loading.value = false
97	    }
98	  }
99	
100	  async function createInspection(receiptId: number, lineId: number, inspectedQty: number, result: 'PASS' | 'FAIL', notes?: string) {
101	    loading.value = true
102	    error.value = null
103	    try {
104	      await api.createInspection({ receiptId, lineId, inspectedQty, result, notes })
105	      await fetchReceipt(receiptId)
106	    } catch (e) {
107	      error.value = normalizeError(e)
108	      throw e
109	    } finally {
110	      loading.value = false
111	    }
112	  }
113	
114	  async function createPutaway(receiptId: number, taskId: number, actualLocation?: string) {
115	    loading.value = true
116	    error.value = null
117	    try {
118	      const res = await api.createPutaway({ receiptId, taskId, actualLocation })
119	      putawayTasks.value = res.data
120	    } catch (e) {
121	      error.value = normalizeError(e)
122	      throw e
123	    } finally {
124	      loading.value = false
125	    }
126	  }
127	
128	  return {
129	    receipts,
130	    currentReceipt,
131	    putawayTasks,
132	    discrepancies,
133	    loading,
134	    error,
135	    totalReceipts,
136	    fetchReceipts,
137	    fetchReceipt,
138	    fetchDiscrepancies,
139	    createReceipt,
140	    transitionReceipt,
141	    createInspection,
142	    createPutaway,
143	  }
144	})
