1	<script setup lang="ts">
2	import { ref, computed } from 'vue'
3	import { useRoute } from 'vue-router'
4	import { useReceiptDetail } from '../composables/useReceiptDetail'
5	import { useWorkflow } from '../composables/useWorkflow'
6	import { useToast } from '@/composables/useToast'
7	import AppCard from '@/components/common/AppCard.vue'
8	import AppButton from '@/components/common/AppButton.vue'
9	import ConfirmDialog from '@/components/feedback/ConfirmDialog.vue'
10	import LoadingState from '@/components/feedback/LoadingState.vue'
11	import ErrorState from '@/components/feedback/ErrorState.vue'
12	import WorkflowProgressIndicator from '../components/WorkflowProgressIndicator.vue'
13	import StatusBadge from '../components/StatusBadge.vue'
14	import ReceivingLineItems from '../components/ReceivingLineItems.vue'
15	import InspectionForm from '../components/InspectionForm.vue'
16	import DiscrepancyCard from '../components/DiscrepancyCard.vue'
17	import PutawayItem from '../components/PutawayItem.vue'
18	
19	const route = useRoute()
20	const toast = useToast()
21	const receiptId = Number(route.params.receiptId)
22	
23	const { receipt, discrepancies, putawayTasks, loading, error, transition, inspect, putaway, refresh } =
24	  useReceiptDetail(receiptId)
25	
26	const { getAvailableTransitions } = useWorkflow()
27	
28	const confirmOpen = ref(false)
29	const pendingTransition = ref<{ status: string; reason: string } | null>(null)
30	
31	const availableTransitions = computed(() => {
32	  if (!receipt.value) return []
33	  return getAvailableTransitions(receipt.value.status)
34	})
35	
36	const isReceiving = computed(() => {
37	  const s = receipt.value?.status?.toLowerCase()
38	  return s === 'in_progress' || s === 'receiving'
39	})
40	
41	const isInspection = computed(() => {
42	  const s = receipt.value?.status?.toLowerCase()
43	  return s === 'inspection'
44	})
45	
46	const isPutaway = computed(() => {
47	  const s = receipt.value?.status?.toLowerCase()
48	  return s === 'putaway'
49	})
50	
51	function requestTransition(targetState: string, reason: string) {
52	  pendingTransition.value = { status: targetState.toLowerCase(), reason }
53	  confirmOpen.value = true
54	}
55	
56	async function confirmTransition() {
57	  if (!pendingTransition.value) return
58	  confirmOpen.value = false
59	  try {
60	    await transition(pendingTransition.value.status)
61	    toast.show('Receipt status updated', 'success')
62	  } catch {
63	    toast.show('Failed to update status', 'error')
64	  }
65	  pendingTransition.value = null
66	}
67	
68	async function handleInspection(data: { lineId: number; inspectedQty: number; result: 'PASS' | 'FAIL'; notes?: string }) {
69	  try {
70	    await inspect(data.lineId, data.inspectedQty, data.result, data.notes)
71	    toast.show('Inspection completed', 'success')
72	  } catch {
73	    toast.show('Inspection failed', 'error')
74	  }
75	}
76	
77	async function handlePutawayConfirm(taskId: number, location: string) {
78	  try {
79	    await putaway(taskId, location)
80	    toast.show(`Putaway confirmed: ${location}`, 'success')
81	  } catch {
82	    toast.show('Putaway failed', 'error')
83	  }
84	}
85	</script>
86	
87	<template>
88	  <div class="receipt-detail">
89	    <LoadingState v-if="loading" text="Loading receipt..." />
90	    <ErrorState v-else-if="error" :message="error.message" @retry="refresh" />
91	
92	    <template v-else-if="receipt">
93	      <!-- Header -->
94	      <div class="receipt-detail__header">
95	        <div>
96	          <h1 class="page-title">{{ receipt.receiptNumber }}</h1>
97	          <p class="receipt-detail__subtitle">
98	            {{ receipt.supplierName }} &middot; <StatusBadge :status="receipt.status" />
99	          </p>
100	        </div>
101	        <div class="receipt-detail__actions">
102	          <AppButton
103	            v-for="t in availableTransitions"
104	            :key="t.targetState"
105	            :variant="t.targetState === 'REJECTED' ? 'danger' : 'primary'"
106	            size="sm"
107	            @click="requestTransition(t.targetState, t.reason ?? '')"
108	          >
109	            {{ t.reason || t.targetState }}
110	          </AppButton>
111	        </div>
112	      </div>
113	
114	      <!-- Workflow -->
115	      <AppCard class="receipt-detail__workflow">
116	        <WorkflowProgressIndicator :current-status="receipt.status" />
117	      </AppCard>
118	
119	      <!-- Line Items -->
120	      <AppCard title="Line Items" padding="none" class="receipt-detail__section">
121	        <ReceivingLineItems :items="receipt.lines" :editable="isReceiving" />
122	      </AppCard>
123	
124	      <!-- Inspection Form -->
125	      <AppCard v-if="isInspection" title="Inspection" class="receipt-detail__section">
126	        <InspectionForm :items="receipt.lines" @submit="handleInspection" />
127	      </AppCard>
128	
129	      <!-- Discrepancies -->
130	      <AppCard
131	        v-if="discrepancies.length > 0"
132	        title="Discrepancies"
133	        class="receipt-detail__section"
134	      >
135	        <div class="receipt-detail__discrepancies">
136	          <DiscrepancyCard
137	            v-for="d in discrepancies"
138	            :key="d.id"
139	            :discrepancy="d"
140	          />
141	        </div>
142	      </AppCard>
143	
144	      <!-- Putaway -->
145	      <AppCard v-if="isPutaway" title="Putaway Tasks" class="receipt-detail__section">
146	        <div class="receipt-detail__putaway">
147	          <PutawayItem
148	            v-for="t in putawayTasks"
149	            :key="t.id"
150	            :task="t"
151	            @confirm="handlePutawayConfirm"
152	          />
153	        </div>
154	        <div v-if="putawayTasks.length === 0" class="receipt-detail__empty">
155	          No putaway tasks assigned yet.
156	        </div>
157	      </AppCard>
158	    </template>
159	
160	    <!-- Confirm Dialog -->
161	    <ConfirmDialog
162	      :open="confirmOpen"
163	      title="Confirm Transition"
164	      :message="`Are you sure you want to ${pendingTransition?.reason ?? 'update the status'}?`"
165	      :variant="pendingTransition?.status === 'rejected' ? 'danger' : 'primary'"
166	      @confirm="confirmTransition"
167	      @cancel="confirmOpen = false"
168	    />
169	  </div>
170	</template>
171	
