30	      stepErrors.value.heightFeet = 'Height must be between 3 and 8 feet'
31	    }
32	    if (form.value.heightInches < 0 || form.value.heightInches > 11) {
33	      stepErrors.value.heightInches = 'Inches must be between 0 and 11'
