1	import { ref, computed, type Ref } from 'vue'
2	
3	type ValidationRule = (value: unknown) => string | null
4	type RulesMap<T> = Partial<Record<keyof T, ValidationRule[]>>
5	
6	export interface FormState<T extends Record<string, unknown>> {
7	  values: Ref<T>
8	  errors: Ref<Partial<Record<keyof T, string>>>
9	  touched: Ref<Partial<Record<keyof T, boolean>>>
10	  isSubmitting: Ref<boolean>
11	  isDirty: Ref<boolean>
12	  setField: <K extends keyof T>(name: K, value: T[K]) => void
13	  setError: (name: keyof T, msg: string) => void
14	  validate: (rules: RulesMap<T>) => boolean
15	  submit: (fn: () => Promise<void>) => Promise<void>
16	  reset: () => void
17	}
18	
19	export function useFormState<T extends Record<string, unknown>>(
20	  initialValues: T,
21	): FormState<T> {
22	  const values = ref<T>({ ...initialValues }) as Ref<T>
23	  const errors = ref<Partial<Record<keyof T, string>>>({})
24	  const touched = ref<Partial<Record<keyof T, boolean>>>({})
25	  const isSubmitting = ref(false)
26	
27	  const originalValues = { ...initialValues }
28	
29	  const isDirty = computed(() => {
30	    const keys = Object.keys(originalValues) as (keyof T)[]
31	    return keys.some((key) => values.value[key] !== originalValues[key])
32	  })
33	
34	  function setField<K extends keyof T>(name: K, value: T[K]) {
35	    values.value[name] = value
36	    touched.value = { ...touched.value, [name]: true }
37	    // Clear error when field changes
38	    if (errors.value[name]) {
39	      const next = { ...errors.value }
40	      delete next[name]
41	      errors.value = next
42	    }
43	  }
44	
45	  function setError(name: keyof T, msg: string) {
46	    errors.value = { ...errors.value, [name]: msg }
47	  }
48	
49	  function validate(rules: RulesMap<T>): boolean {
50	    const newErrors: Partial<Record<keyof T, string>> = {}
51	    let valid = true
52	
53	    for (const [field, fieldRules] of Object.entries(rules)) {
54	      if (!fieldRules) continue
55	      const value = values.value[field as keyof T]
56	      for (const rule of fieldRules as ValidationRule[]) {
57	        const errorMsg = rule(value)
58	        if (errorMsg) {
59	          newErrors[field as keyof T] = errorMsg
60	          valid = false
61	          break
62	        }
63	      }
64	    }
65	
66	    errors.value = newErrors
67	    return valid
68	  }
69	
70	  async function submit(fn: () => Promise<void>) {
71	    isSubmitting.value = true
72	    try {
73	      await fn()
74	    } finally {
75	      isSubmitting.value = false
76	    }
77	  }
78	
79	  function reset() {
80	    values.value = { ...initialValues } as T
81	    errors.value = {}
82	    touched.value = {}
83	    isSubmitting.value = false
84	  }
85	
86	  return {
87	    values,
88	    errors,
89	    touched,
90	    isSubmitting,
91	    isDirty: isDirty as unknown as Ref<boolean>,
92	    setField,
93	    setError,
94	    validate,
95	    submit,
96	    reset,
97	  }
98	}
