1	import { defineStore } from 'pinia'
2	import { ref } from 'vue'
3	import type {
4	  MasterDataItem,
5	  ImportResult,
6	  MergeCandidate,
7	  ChangeHistoryEntry,
8	} from '@/services/adapters/api-adapter.interface'
9	import { masterDataApi } from './api'
10	import { normalizeError } from '@/utils/error-normalizer'
11	import type { ApiError } from '@/types/api'
12	
13	export const useMasterDataStore = defineStore('master-data', () => {
14	  const items = ref<MasterDataItem[]>([])
15	  const totalItems = ref(0)
16	  const importResult = ref<ImportResult | null>(null)
17	  const mergeCandidates = ref<MergeCandidate[]>([])
18	  const changeHistory = ref<ChangeHistoryEntry[]>([])
19	  const loading = ref(false)
20	  const error = ref<ApiError | null>(null)
21	
22	  const api = masterDataApi()
23	
24	  async function fetchItems(type?: string, page = 0, size = 20) {
25	    loading.value = true
26	    error.value = null
27	    try {
28	      const res = await api.getItems(type, { page, size })
29	      const payload = res.data as any
30	      if (Array.isArray(payload)) {
31	        items.value = payload
32	        totalItems.value = payload.length
33	      } else if (payload && Array.isArray(payload.content)) {
34	        items.value = payload.content
35	        totalItems.value = payload.totalElements ?? payload.content.length
36	      } else {
37	        items.value = []
38	        totalItems.value = 0
39	      }
40	    } catch (e) {
41	      error.value = normalizeError(e)
42	    } finally {
43	      loading.value = false
44	    }
45	  }
46	
47	  async function importFile(file: File, type: string) {
48	    loading.value = true
49	    error.value = null
50	    try {
51	      const res = await api.importFile(file, type)
52	      importResult.value = res.data
53	    } catch (e) {
54	      error.value = normalizeError(e)
55	      throw e
56	    } finally {
57	      loading.value = false
58	    }
59	  }
60	
61	  async function fetchMergeCandidates(type: string) {
62	    loading.value = true
63	    error.value = null
64	    try {
65	      const res = await api.getMergeCandidates(type)
66	      mergeCandidates.value = res.data
67	    } catch (e) {
68	      error.value = normalizeError(e)
69	    } finally {
70	      loading.value = false
71	    }
72	  }
73	
74	  async function executeMerge(entityType: string, sourceId: number, targetId: number) {
75	    loading.value = true
76	    error.value = null
77	    try {
78	      await api.executeMerge(entityType, sourceId, targetId)
79	      // Remove merged candidate
80	      mergeCandidates.value = mergeCandidates.value.filter(
81	        c => !(c.sourceItem.id === sourceId && c.targetItem.id === targetId)
82	      )
83	    } catch (e) {
84	      error.value = normalizeError(e)
85	      throw e
86	    } finally {
87	      loading.value = false
88	    }
89	  }
90	
91	  async function fetchHistory(entityType?: string, entityId?: number) {
92	    loading.value = true
93	    error.value = null
94	    try {
95	      const res = await api.getHistory(entityType, entityId)
96	      changeHistory.value = res.data
97	    } catch (e) {
98	      error.value = normalizeError(e)
99	    } finally {
100	      loading.value = false
101	    }
102	  }
103	
104	  return {
105	    items,
106	    totalItems,
107	    importResult,
108	    mergeCandidates,
109	    changeHistory,
110	    loading,
111	    error,
112	    fetchItems,
113	    importFile,
114	    fetchMergeCandidates,
115	    executeMerge,
116	    fetchHistory,
117	  }
118	})
