1	package com.campusfit.fitness.service;
2	
3	import com.campusfit.fitness.dto.GoalRequest;
4	import com.campusfit.fitness.dto.GoalResponse;
5	import com.campusfit.fitness.entity.Assessment;
6	import com.campusfit.fitness.entity.Goal;
7	import com.campusfit.fitness.entity.Milestone;
8	import com.campusfit.fitness.repository.AssessmentRepository;
9	import com.campusfit.fitness.repository.GoalRepository;
10	import com.campusfit.fitness.repository.MilestoneRepository;
11	import com.campusfit.shared.exception.BusinessException;
12	import com.campusfit.shared.exception.ResourceNotFoundException;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import java.math.BigDecimal;
17	import java.math.RoundingMode;
18	import java.time.LocalDate;
19	import java.time.temporal.ChronoUnit;
20	import java.util.ArrayList;
21	import java.util.List;
22	import java.util.stream.Collectors;
23	
24	@Service
25	public class GoalService {
26	
27	    private static final int DEFAULT_MILESTONE_COUNT = 4;
28	
29	    private final GoalRepository goalRepository;
30	    private final MilestoneRepository milestoneRepository;
31	    private final AssessmentRepository assessmentRepository;
32	
33	    public GoalService(GoalRepository goalRepository,
34	                       MilestoneRepository milestoneRepository,
35	                       AssessmentRepository assessmentRepository) {
36	        this.goalRepository = goalRepository;
37	        this.milestoneRepository = milestoneRepository;
38	        this.assessmentRepository = assessmentRepository;
39	    }
40	
41	    @Transactional
42	    public GoalResponse create(Long userId, GoalRequest request) {
43	        // Resolve baseline from latest assessment
44	        BigDecimal startValue = BigDecimal.ZERO;
45	        Long assessmentId = null;
46	        Assessment latestAssessment = assessmentRepository
47	                .findTopByUserIdOrderByAssessmentDateDesc(userId).orElse(null);
48	        if (latestAssessment != null) {
49	            assessmentId = latestAssessment.getId();
50	            startValue = resolveBaselineFromAssessment(latestAssessment, request.getGoalType());
51	        }
52	
53	        Goal goal = Goal.builder()
54	                .userId(userId)
55	                .assessmentId(assessmentId)
56	                .goalType(request.getGoalType())
57	                .description(request.getDescription())
58	                .targetValue(request.getTargetValue())
59	                .startValue(startValue)
60	                .currentValue(startValue)
61	                .unit(request.getUnit())
62	                .startDate(request.getStartDate())
63	                .targetDate(request.getTargetDate())
64	                .status(Goal.GoalStatus.ACTIVE)
65	                .missedCheckIns(0)
66	                .metricsEncrypted("{\"targetValue\":" + request.getTargetValue() + ",\"startValue\":" + startValue + "}")
67	                .build();
68	
69	        Goal saved = goalRepository.save(goal);
70	
71	        // Generate milestones evenly spaced across goal period
72	        generateMilestones(saved);
73	
74	        List<Milestone> milestones = milestoneRepository.findByGoalIdOrderBySeq(saved.getId());
75	        return toResponse(saved, milestones);
76	    }
77	
78	    @Transactional
79	    public GoalResponse update(Long goalId, Long userId, GoalRequest request) {
80	        Goal goal = goalRepository.findById(goalId)
81	                .orElseThrow(() -> new ResourceNotFoundException("Goal", goalId));
82	
83	        if (!goal.getUserId().equals(userId)) {
84	            throw new BusinessException("You do not have permission to update this goal");
85	        }
86	
87	        goal.setGoalType(request.getGoalType());
88	        goal.setDescription(request.getDescription());
89	        goal.setTargetValue(request.getTargetValue());
90	        goal.setUnit(request.getUnit());
91	        goal.setStartDate(request.getStartDate());
92	        goal.setTargetDate(request.getTargetDate());
93	
94	        Goal saved = goalRepository.save(goal);
95	        List<Milestone> milestones = milestoneRepository.findByGoalIdOrderBySeq(saved.getId());
96	        return toResponse(saved, milestones);
97	    }
98	
99	    @Transactional(readOnly = true)
100	    public GoalResponse getById(Long goalId, Long userId) {
101	        Goal goal = goalRepository.findById(goalId)
102	                .orElseThrow(() -> new ResourceNotFoundException("Goal", goalId));
103	
104	        if (!goal.getUserId().equals(userId)) {
105	            throw new BusinessException("You do not have permission to view this goal");
106	        }
107	
108	        List<Milestone> milestones = milestoneRepository.findByGoalIdOrderBySeq(goalId);
109	        return toResponse(goal, milestones);
110	    }
111	
112	    @Transactional(readOnly = true)
113	    public List<GoalResponse> getAllForUser(Long userId) {
114	        List<Goal> goals = goalRepository.findByUserId(userId);
115	        return goals.stream()
116	                .map(g -> {
117	                    List<Milestone> milestones = milestoneRepository.findByGoalIdOrderBySeq(g.getId());
118	                    return toResponse(g, milestones);
119	                })
120	                .collect(Collectors.toList());
121	    }
122	
123	    private void generateMilestones(Goal goal) {
124	        long totalDays = ChronoUnit.DAYS.between(goal.getStartDate(), goal.getTargetDate());
125	        if (totalDays <= 0) {
126	            return;
127	        }
128	
129	        BigDecimal totalChange = goal.getTargetValue().subtract(goal.getStartValue());
130	        int milestoneCount = DEFAULT_MILESTONE_COUNT;
131	        List<Milestone> milestones = new ArrayList<>();
132	
133	        for (int i = 1; i <= milestoneCount; i++) {
134	            BigDecimal fraction = BigDecimal.valueOf(i).divide(BigDecimal.valueOf(milestoneCount), 4, RoundingMode.HALF_UP);
135	            BigDecimal milestoneValue = goal.getStartValue().add(
136	                    totalChange.multiply(fraction).setScale(2, RoundingMode.HALF_UP)
137	            );
138	
139	            Milestone milestone = Milestone.builder()
140	                    .goalId(goal.getId())
141	                    .description("Milestone " + i + " of " + milestoneCount)
142	                    .targetValue(milestoneValue)
143	                    .seq(i)
144	                    .build();
145	            milestones.add(milestone);
146	        }
147	
148	        milestoneRepository.saveAll(milestones);
149	    }
150	
151	    private GoalResponse toResponse(Goal goal, List<Milestone> milestones) {
152	        double progressPercentage = calculateProgress(goal);
153	
154	        List<GoalResponse.MilestoneResponse> milestoneResponses = milestones.stream()
155	                .map(m -> GoalResponse.MilestoneResponse.builder()
156	                        .id(m.getId())
157	                        .description(m.getDescription())
158	                        .targetValue(m.getTargetValue())
159	                        .achievedDate(m.getAchievedDate())
160	                        .seq(m.getSeq())
161	                        .build())
162	                .collect(Collectors.toList());
163	
164	        return GoalResponse.builder()
165	                .id(goal.getId())
166	                .userId(goal.getUserId())
167	                .assessmentId(goal.getAssessmentId())
168	                .goalType(goal.getGoalType())
169	                .description(goal.getDescription())
170	                .targetValue(goal.getTargetValue())
171	                .startValue(goal.getStartValue())
172	                .currentValue(goal.getCurrentValue())
173	                .unit(goal.getUnit())
174	                .startDate(goal.getStartDate())
175	                .targetDate(goal.getTargetDate())
176	                .status(goal.getStatus())
177	                .missedCheckIns(goal.getMissedCheckIns())
178	                .progressPercentage(progressPercentage)
179	                .milestones(milestoneResponses)
180	                .createdAt(goal.getCreatedAt())
181	                .updatedAt(goal.getUpdatedAt())
182	                .build();
183	    }
184	
185	    private BigDecimal resolveBaselineFromAssessment(Assessment assessment, Goal.GoalType goalType) {
186	        if (assessment == null) return BigDecimal.ZERO;
187	        switch (goalType) {
188	            case WEIGHT_LOSS:
189	            case WEIGHT_GAIN:
190	                Double weight = assessment.getWeightLbs();
191	                return weight != null ? BigDecimal.valueOf(weight) : BigDecimal.ZERO;
192	            case FLEXIBILITY:
193	            case ENDURANCE:
194	            case STRENGTH:
195	            default:
196	                return BigDecimal.ZERO;
197	        }
198	    }
199	
200	    private double calculateProgress(Goal goal) {
201	        BigDecimal totalChange = goal.getTargetValue().subtract(goal.getStartValue());
202	        if (totalChange.compareTo(BigDecimal.ZERO) == 0) {
203	            return 100.0;
204	        }
205	        BigDecimal currentChange = goal.getCurrentValue().subtract(goal.getStartValue());
206	        return currentChange.divide(totalChange, 4, RoundingMode.HALF_UP)
207	                .multiply(BigDecimal.valueOf(100))
208	                .doubleValue();
209	    }
210	}
