48	        // Determine the next week number based on elapsed time from goal start
49	        List<CheckIn> existingCheckIns = checkInRepository.findByGoalIdOrderByWeekNumberDesc(goalId);
50	        long weeksElapsed = ChronoUnit.WEEKS.between(goal.getStartDate().atStartOfDay(), LocalDateTime.now());
51	        int currentWeek = Math.max(1, (int) weeksElapsed + 1);
52	        int lastRecordedWeek = existingCheckIns.isEmpty() ? 0 : existingCheckIns.get(0).getWeekNumber();
53	        int nextWeekNumber = Math.max(currentWeek, lastRecordedWeek + 1);
54	
55	        // Calculate missed weeks based on gap since last check-in
56	        int missedWeeks = nextWeekNumber - lastRecordedWeek - 1;
57	
58	        CheckIn checkIn = CheckIn.builder()
59	                .goalId(goalId)
60	                .userId(userId)
61	                .weekNumber(nextWeekNumber)
62	                .value(request.getValue())
63	                .valueEncrypted(request.getValue().toPlainString())
64	                .notes(request.getNotes())
65	                .build();
66	
67	        CheckIn saved = checkInRepository.save(checkIn);
68	
69	        // Update goal's current value
70	        goal.setCurrentValue(request.getValue());
71	
72	        // Track consecutive missed check-ins
73	        if (missedWeeks > 0) {
74	            goal.setMissedCheckIns(goal.getMissedCheckIns() + missedWeeks);
75	        } else {
76	            // Successful check-in resets missed counter
77	            goal.setMissedCheckIns(0);
78	        }
79	
80	        // Check if consecutive missed check-ins >= 2
81	        if (goal.getMissedCheckIns() >= 2) {
82	            recalculationPolicy.recalculate(goal, userId);
83	        } else {
84	            goalRepository.save(goal);
85	        }
86	
87	        // Check if goal is achieved
88	        if (request.getValue().compareTo(goal.getTargetValue()) >= 0) {
89	            goal.setStatus(Goal.GoalStatus.ACHIEVED);
90	            goalRepository.save(goal);
91	        }
92	
93	        return toResponse(saved);
94	    }
