96	    @Transactional(readOnly = true)
97	    public List<CheckInResponse> getByGoalId(Long goalId, Long userId) {
98	        Goal goal = goalRepository.findById(goalId)
99	                .orElseThrow(() -> new ResourceNotFoundException("Goal", goalId));
100	
101	        if (!goal.getUserId().equals(userId)) {
102	            throw new BusinessException("You do not have permission to view check-ins for this goal");
103	        }
104	
105	        return checkInRepository.findByGoalIdOrderByWeekNumberDesc(goalId).stream()
106	                .map(this::toResponse)
107	                .collect(Collectors.toList());
108	    }
