8	import com.campusfit.shared.exception.ResourceNotFoundException;
9	import com.fasterxml.jackson.databind.ObjectMapper;
10	import org.slf4j.Logger;
11	import org.slf4j.LoggerFactory;
12	import org.springframework.stereotype.Service;
13	import org.springframework.transaction.annotation.Transactional;
14	
15	import java.time.LocalDate;
16	import java.util.LinkedHashMap;
17	import java.util.List;
18	import java.util.Map;
19	import java.util.stream.Collectors;
20	
21	@Service
22	public class AssessmentService {
23	
24	    private static final Logger log = LoggerFactory.getLogger(AssessmentService.class);
25	
26	    private final AssessmentRepository assessmentRepository;
27	    private final ObjectMapper objectMapper;
28	
29	    public AssessmentService(AssessmentRepository assessmentRepository) {
30	        this.assessmentRepository = assessmentRepository;
31	        this.objectMapper = new ObjectMapper();
32	    }
33	
34	    @Transactional
35	    public AssessmentResponse createOrUpdate(Long userId, AssessmentRequest request) {
36	        String encryptedMetrics = buildEncryptedMetrics(request);
37	
38	        Assessment assessment = Assessment.builder()
39	                .userId(userId)
40	                .assessmentType("INITIAL")
41	                .metricsEncrypted(encryptedMetrics)
42	                .assessmentDate(LocalDate.now())
43	                .notes(request.getNotes())
44	                .build();
45	
46	        List<Assessment> existing = assessmentRepository.findByUserId(userId);
47	        if (!existing.isEmpty()) {
48	            assessment.setAssessmentType("PERIODIC");
49	        }
50	
51	        Assessment saved = assessmentRepository.save(assessment);
52	        return toResponse(saved, request);
53	    }
54	
55	    @Transactional(readOnly = true)
56	    public AssessmentResponse getLatest(Long userId) {
57	        Assessment assessment = assessmentRepository.findTopByUserIdOrderByAssessmentDateDesc(userId)
58	                .orElseThrow(() -> new ResourceNotFoundException("Assessment", userId));
59	        return toResponse(assessment, null);
60	    }
61	
62	    @Transactional(readOnly = true)
63	    public List<AssessmentResponse> getAllForUser(Long userId) {
64	        return assessmentRepository.findByUserId(userId).stream()
65	                .map(a -> toResponse(a, null))
66	                .collect(Collectors.toList());
67	    }
68	
69	    @Transactional
70	    public AssessmentResponse update(Long assessmentId, Long userId, AssessmentRequest request) {
71	        Assessment assessment = assessmentRepository.findById(assessmentId)
72	                .orElseThrow(() -> new ResourceNotFoundException("Assessment", assessmentId));
73	
74	        if (!assessment.getUserId().equals(userId)) {
75	            throw new BusinessException("You do not have permission to update this assessment");
76	        }
77	
78	        assessment.setMetricsEncrypted(buildEncryptedMetrics(request));
79	        assessment.setNotes(request.getNotes());
80	
81	        Assessment saved = assessmentRepository.save(assessment);
82	        return toResponse(saved, request);
83	    }
84	
85	    private String buildEncryptedMetrics(AssessmentRequest request) {
86	        try {
87	            Map<String, Object> metrics = new LinkedHashMap<>();
88	            metrics.put("heightFeet", request.getHeightFeet());
89	            metrics.put("heightInches", request.getHeightInches());
90	            metrics.put("weightLbs", request.getWeightLbs());
91	            metrics.put("bodyFatPercent", request.getBodyFatPercent());
92	            metrics.put("waist", request.getWaist());
93	            metrics.put("chest", request.getChest());
94	            metrics.put("arm", request.getArm());
95	            return objectMapper.writeValueAsString(metrics);
96	        } catch (Exception e) {
97	            throw new BusinessException("Failed to serialize metrics for encryption: " + e.getMessage());
98	        }
99	    }
100	
101	    @SuppressWarnings("unchecked")
102	    private Map<String, Object> parseEncryptedMetrics(String encrypted) {
103	        if (encrypted == null || encrypted.isBlank() || "PENDING_MIGRATION".equals(encrypted)) {
104	            return Map.of();
105	        }
106	        try {
107	            return objectMapper.readValue(encrypted, Map.class);
108	        } catch (Exception e) {
109	            log.warn("Failed to parse encrypted metrics: {}", e.getMessage());
110	            return Map.of();
111	        }
112	    }
113	
114	    private AssessmentResponse toResponse(Assessment a, AssessmentRequest originalRequest) {
115	        // Read metrics from encrypted field (authoritative source)
116	        Map<String, Object> metrics = parseEncryptedMetrics(a.getMetricsEncrypted());
117	
118	        int heightFeet = getInt(metrics, "heightFeet", a.getHeightFeet());
119	        int heightInches = getInt(metrics, "heightInches", a.getHeightInches());
120	        double weightLbs = getDouble(metrics, "weightLbs", a.getWeightLbs());
121	        Double bodyFatPercent = getOptionalDouble(metrics, "bodyFatPercent", a.getBodyFatPercent());
122	        Double waistInches = getOptionalDouble(metrics, "waist", a.getWaistInches());
123	        Double chestInches = getOptionalDouble(metrics, "chest", a.getChestInches());
124	        Double armInches = getOptionalDouble(metrics, "arm", a.getArmInches());
125	
126	        // If we have the original request, prefer those values for immediate response
127	        if (originalRequest != null) {
128	            heightFeet = originalRequest.getHeightFeet();
129	            heightInches = originalRequest.getHeightInches();
130	            weightLbs = originalRequest.getWeightLbs();
131	            bodyFatPercent = originalRequest.getBodyFatPercent();
132	            waistInches = originalRequest.getWaist();
133	            chestInches = originalRequest.getChest();
134	            armInches = originalRequest.getArm();
135	        }
136	
137	        String formattedHeight = heightFeet + "'" + heightInches + "\"";
138	
139	        return AssessmentResponse.builder()
140	                .id(a.getId())
141	                .userId(a.getUserId())
142	                .assessmentType(a.getAssessmentType())
143	                .heightFeet(heightFeet)
144	                .heightInches(heightInches)
145	                .formattedHeight(formattedHeight)
146	                .weightLbs(weightLbs)
147	                .bodyFatPercent(bodyFatPercent)
148	                .waistInches(waistInches)
149	                .chestInches(chestInches)
150	                .armInches(armInches)
151	                .assessmentDate(a.getAssessmentDate())
152	                .notes(a.getNotes())
153	                .createdAt(a.getCreatedAt())
154	                .updatedAt(a.getUpdatedAt())
155	                .build();
156	    }
157	
158	    private int getInt(Map<String, Object> map, String key, Integer fallback) {
159	        Object val = map.get(key);
160	        if (val instanceof Number) return ((Number) val).intValue();
161	        return fallback != null ? fallback : 0;
162	    }
163	
164	    private double getDouble(Map<String, Object> map, String key, Double fallback) {
165	        Object val = map.get(key);
166	        if (val instanceof Number) return ((Number) val).doubleValue();
167	        return fallback != null ? fallback : 0.0;
168	    }
169	
170	    private Double getOptionalDouble(Map<String, Object> map, String key, Double fallback) {
171	        Object val = map.get(key);
172	        if (val instanceof Number) return ((Number) val).doubleValue();
173	        return fallback;
174	    }
175	}
