1	package com.campusfit.shared.encryption;
2	
3	import javax.crypto.Cipher;
4	import javax.crypto.SecretKey;
5	import javax.crypto.spec.GCMParameterSpec;
6	import javax.crypto.spec.SecretKeySpec;
7	import java.nio.ByteBuffer;
8	import java.nio.charset.StandardCharsets;
9	import java.security.SecureRandom;
10	import java.util.Base64;
11	
12	public class EncryptionService {
13	
14	    private static final String ALGORITHM = "AES/GCM/NoPadding";
15	    private static final int GCM_IV_LENGTH = 12;
16	    private static final int GCM_TAG_LENGTH = 128;
17	
18	    private final SecretKey secretKey;
19	    private final SecureRandom secureRandom;
20	
21	    public EncryptionService(String hexKey) {
22	        byte[] keyBytes = hexStringToBytes(hexKey);
23	        this.secretKey = new SecretKeySpec(keyBytes, "AES");
24	        this.secureRandom = new SecureRandom();
25	    }
26	
27	    public String encrypt(String plaintext) {
28	        if (plaintext == null) {
29	            return null;
30	        }
31	        try {
32	            byte[] iv = new byte[GCM_IV_LENGTH];
33	            secureRandom.nextBytes(iv);
34	
35	            Cipher cipher = Cipher.getInstance(ALGORITHM);
36	            GCMParameterSpec parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
37	            cipher.init(Cipher.ENCRYPT_MODE, secretKey, parameterSpec);
38	
39	            byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
40	
41	            ByteBuffer byteBuffer = ByteBuffer.allocate(iv.length + ciphertext.length);
42	            byteBuffer.put(iv);
43	            byteBuffer.put(ciphertext);
44	
45	            return Base64.getEncoder().encodeToString(byteBuffer.array());
46	        } catch (Exception e) {
47	            throw new RuntimeException("Encryption failed", e);
48	        }
49	    }
50	
51	    public String decrypt(String ciphertext) {
52	        if (ciphertext == null) {
53	            return null;
54	        }
55	        try {
56	            byte[] decoded = Base64.getDecoder().decode(ciphertext);
57	
58	            ByteBuffer byteBuffer = ByteBuffer.wrap(decoded);
59	            byte[] iv = new byte[GCM_IV_LENGTH];
60	            byteBuffer.get(iv);
61	            byte[] encrypted = new byte[byteBuffer.remaining()];
62	            byteBuffer.get(encrypted);
63	
64	            Cipher cipher = Cipher.getInstance(ALGORITHM);
65	            GCMParameterSpec parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
66	            cipher.init(Cipher.DECRYPT_MODE, secretKey, parameterSpec);
67	
68	            byte[] plaintext = cipher.doFinal(encrypted);
69	            return new String(plaintext, StandardCharsets.UTF_8);
70	        } catch (Exception e) {
71	            throw new RuntimeException("Decryption failed", e);
72	        }
73	    }
74	
75	    private static byte[] hexStringToBytes(String hex) {
76	        int len = hex.length();
77	        byte[] data = new byte[len / 2];
78	        for (int i = 0; i < len; i += 2) {
79	            data[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4)
80	                + Character.digit(hex.charAt(i + 1), 16));
81	        }
82	        return data;
83	    }
84	}
