2	import { usePutaway } from '../composables/usePutaway'
3	import { useOperationsStore } from '../store'
4	import { useToast } from '@/composables/useToast'
5	import PutawayItem from '../components/PutawayItem.vue'
6	import AppButton from '@/components/common/AppButton.vue'
7	import LoadingState from '@/components/feedback/LoadingState.vue'
8	import ErrorState from '@/components/feedback/ErrorState.vue'
9	import EmptyState from '@/components/feedback/EmptyState.vue'
10	
11	const toast = useToast()
12	const store = useOperationsStore()
13	const { pendingTasks, completedTasks, loading, error } = usePutaway()
14	
15	async function handleConfirm(taskId: number, location: string) {
16	  const task = pendingTasks.value.find(t => t.id === taskId)
17	  if (!task) return
18	  try {
19	    await store.createPutaway(task.receiptId, taskId, location)
20	    toast.show(`Task ${taskId} confirmed at ${location}`, 'success')
21	  } catch {
22	    toast.show('Putaway failed', 'error')
23	  }
24	}
25	
26	async function bulkComplete() {
27	  for (const task of pendingTasks.value) {
28	    try {
29	      await store.createPutaway(task.receiptId, task.id, task.suggestedLocation)
30	    } catch {
31	      toast.show(`Failed to complete task ${task.id}`, 'error')
32	      return
33	    }
34	  }
35	  toast.show('All tasks completed', 'success')
36	}
37	</script>
38	
39	<template>
40	  <div class="putaway-page">
41	    <div class="putaway-page__header">
42	      <h1 class="page-title">Putaway Queue</h1>
43	      <AppButton
44	        v-if="pendingTasks.length > 1"
45	        variant="secondary"
46	        @click="bulkComplete"
47	      >
48	        Bulk Complete
49	      </AppButton>
50	    </div>
51	
52	    <LoadingState v-if="loading" text="Loading putaway tasks..." />
53	    <ErrorState v-else-if="error" :message="error.message" />
54	    <EmptyState
55	      v-else-if="pendingTasks.length === 0 && completedTasks.length === 0"
56	      title="No putaway tasks"
57	      message="There are no putaway tasks in the queue."
58	    />
59	
60	    <template v-else>
61	      <section v-if="pendingTasks.length > 0" class="putaway-page__section">
62	        <h2 class="putaway-page__section-title">
63	          Pending ({{ pendingTasks.length }})
64	        </h2>
65	        <div class="putaway-page__grid">
66	          <PutawayItem
67	            v-for="task in pendingTasks"
68	            :key="task.id"
69	            :task="task"
70	            @confirm="handleConfirm"
71	          />
72	        </div>
73	      </section>
74	
75	      <section v-if="completedTasks.length > 0" class="putaway-page__section">
76	        <h2 class="putaway-page__section-title">
77	          Completed ({{ completedTasks.length }})
78	        </h2>
79	        <div class="putaway-page__grid">
80	          <PutawayItem
81	            v-for="task in completedTasks"
82	            :key="task.id"
83	            :task="task"
84	            @confirm="handleConfirm"
85	          />
86	        </div>
87	      </section>
88	    </template>
89	  </div>
90	</template>
