31	
32	    public AccountImportService(StudyExportImportService studyExportImportService,
33	                                AssessmentService assessmentService,
34	                                GoalService goalService,
35	                                CheckInService checkInService) {
36	        this.studyExportImportService = studyExportImportService;
37	        this.assessmentService = assessmentService;
38	        this.goalService = goalService;
39	        this.checkInService = checkInService;
40	        this.objectMapper = new ObjectMapper();
41	        this.objectMapper.registerModule(new JavaTimeModule());
42	    }
43	
44	    @Transactional
45	    public String importAccountData(Long userId, Map<String, Object> data) {
46	        int studyCount = 0;
47	        int fitnessCount = 0;
48	        int goalCount = 0;
49	        int checkInCount = 0;
50	
51	        // Import study data if present
52	        if (data.containsKey("studyData")) {
53	            try {
54	                StudyExportData studyData = objectMapper.convertValue(data.get("studyData"), StudyExportData.class);
55	                studyExportImportService.importData(userId, studyData);
56	                studyCount++;
57	            } catch (Exception e) {
58	                log.warn("Failed to import study data: {}", e.getMessage());
59	            }
60	        }
61	
62	        // Import fitness assessments if present
63	        if (data.containsKey("fitnessData")) {
64	            try {
65	                @SuppressWarnings("unchecked")
66	                List<Map<String, Object>> fitnessDataList = (List<Map<String, Object>>) data.get("fitnessData");
67	                for (Map<String, Object> assessmentData : fitnessDataList) {
68	                    AssessmentRequest request = objectMapper.convertValue(assessmentData, AssessmentRequest.class);
69	                    assessmentService.createOrUpdate(userId, request);
70	                    fitnessCount++;
71	                }
72	            } catch (Exception e) {
73	                log.warn("Failed to import fitness data: {}", e.getMessage());
74	            }
75	        }
76	
77	        // Import goals if present
78	        if (data.containsKey("goalsData")) {
79	            try {
80	                @SuppressWarnings("unchecked")
81	                List<Map<String, Object>> goalsDataList = (List<Map<String, Object>>) data.get("goalsData");
82	                for (Map<String, Object> goalData : goalsDataList) {
83	                    GoalRequest request = objectMapper.convertValue(goalData, GoalRequest.class);
84	                    goalService.create(userId, request);
85	                    goalCount++;
86	                }
87	            } catch (Exception e) {
88	                log.warn("Failed to import goals data: {}", e.getMessage());
89	            }
90	        }
91	
92	        // Import check-ins if present
93	        if (data.containsKey("checkInsData")) {
94	            try {
95	                @SuppressWarnings("unchecked")
96	                List<Map<String, Object>> checkInsDataList = (List<Map<String, Object>>) data.get("checkInsData");
97	                for (Map<String, Object> checkInData : checkInsDataList) {
98	                    Long goalId = checkInData.get("goalId") != null
99	                            ? ((Number) checkInData.get("goalId")).longValue() : null;
100	                    if (goalId != null) {
101	                        CheckInRequest request = objectMapper.convertValue(checkInData, CheckInRequest.class);
102	                        checkInService.create(goalId, userId, request);
103	                        checkInCount++;
104	                    }
105	                }
106	            } catch (Exception e) {
107	                log.warn("Failed to import check-ins data: {}", e.getMessage());
108	            }
109	        }
110	
111	        return String.format("Import completed. Study: %d, Assessments: %d, Goals: %d, Check-ins: %d",
112	                studyCount, fitnessCount, goalCount, checkInCount);
113	    }
