191	            profile.put("username", user.getUsername());
192	            profile.put("email", user.getEmail());
193	            profile.put("phone", user.getPhone());
194	            profile.put("createdAt", user.getCreatedAt() != null ? user.getCreatedAt().toString() : null);
195	            exportBundle.put("profileData", profile);
196	        });
197	    }
