199	    private void addCheckInsForGoals(java.util.Map<String, Object> exportBundle,
200	                                     List<GoalResponse> goals, Long userId) {
201	        java.util.List<Object> allCheckIns = new java.util.ArrayList<>();
202	        for (GoalResponse goal : goals) {
203	            try {
204	                allCheckIns.addAll(checkInService.getByGoalId(goal.getId(), userId));
205	            } catch (Exception ignored) { }
206	        }
207	        exportBundle.put("checkInsData", allCheckIns);
