210	    private String maskNestedUserIds(String json, Long userId) {
211	        String maskedId = fieldMasker.mask(String.valueOf(userId));
212	        // Replace all occurrences of "userId":123 with the masked value
213	        return json.replaceAll("\"userId\"\\s*:\\s*" + userId, "\"userId\":" + maskedId.hashCode());
214	    }
