216	    private String writeExportFile(Long userId, Long jobId, String data,
217	                                    boolean passwordProtected, String password) throws IOException {
218	        Path userDir = Paths.get(exportBaseDir, "user-" + userId);
219	        Files.createDirectories(userDir);
220	
221	        String fileName = "export-" + jobId + ".enc";
222	        Path filePath = userDir.resolve(fileName);
223	
224	        byte[] content = data.getBytes(java.nio.charset.StandardCharsets.UTF_8);
225	        content = encryptWithPassword(content, password);
226	
227	        Files.write(filePath, content);
228	        return filePath.toString();
229	    }
230	
231	    private byte[] encryptWithPassword(byte[] data, String password) {
232	        try {
233	            SecureRandom random = new SecureRandom();
234	            byte[] salt = new byte[16];
235	            random.nextBytes(salt);
236	            byte[] iv = new byte[16];
237	            random.nextBytes(iv);
238	
239	            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
240	            PBEKeySpec spec = new PBEKeySpec(password.toCharArray(), salt, 65536, 256);
241	            SecretKeySpec keySpec = new SecretKeySpec(factory.generateSecret(spec).getEncoded(), "AES");
242	
243	            Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
244	            cipher.init(Cipher.ENCRYPT_MODE, keySpec, new IvParameterSpec(iv));
245	            byte[] encrypted = cipher.doFinal(data);
246	
247	            // Prepend salt + IV to encrypted data
248	            byte[] result = new byte[salt.length + iv.length + encrypted.length];
249	            System.arraycopy(salt, 0, result, 0, salt.length);
250	            System.arraycopy(iv, 0, result, salt.length, iv.length);
251	            System.arraycopy(encrypted, 0, result, salt.length + iv.length, encrypted.length);
252	            return result;
253	        } catch (Exception e) {
254	            throw new BusinessException("Failed to encrypt export file: " + e.getMessage());
255	        }
256	    }
257	
258	    private ExportResponse toResponse(ExportJob job) {
259	        return ExportResponse.builder()
260	                .id(job.getId())
261	                .userId(job.getUserId())
262	                .exportType(job.getExportType())
263	                .status(job.getStatus())
264	                .downloadReady(job.getFilePath() != null && job.getStatus() == ExportJob.JobStatus.COMPLETED)
265	                .passwordProtected(job.isPasswordProtected())
266	                .expiresAt(job.getExpiresAt())
267	                .createdAt(job.getCreatedAt())
268	                .completedAt(job.getCompletedAt())
269	                .build();
270	    }
271	}
