49	    public PutawayTask completeTask(Long receiptId, Long taskId, Long userId, String actualLocation) {
50	        PutawayTask task = putawayTaskRepository.findById(taskId)
51	                .orElseThrow(() -> new ResourceNotFoundException("PutawayTask", taskId));
52	
53	        if (!task.getReceiptId().equals(receiptId)) {
