86	            for (int i = 0; i < rows.size(); i++) {
87	                int rowNum = i + 2; // 1-based, skip header
88	                totalRows++;
89	                String[] fields = rows.get(i);
90	                try {
91	                    if (fields.length < 2) {
92	                        errors.add(buildError(job.getId(), rowNum, "line",
93	                                "Insufficient fields - expected at least code,name", String.join(",", fields)));
94	                        continue;
95	                    }
