143	    private List<String[]> parseCsv(InputStream inputStream) throws Exception {
144	        List<String[]> rows = new ArrayList<>();
145	        try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
146	            reader.readLine(); // skip header
147	            String line;
148	            while ((line = reader.readLine()) != null) {
149	                if (!line.trim().isEmpty()) {
150	                    rows.add(line.split(","));
151	                }
152	            }
153	        }
154	        return rows;
155	    }
156	
157	    private List<String[]> parseExcel(InputStream inputStream) throws Exception {
158	        List<String[]> rows = new ArrayList<>();
159	        try (Workbook workbook = new XSSFWorkbook(inputStream)) {
160	            Sheet sheet = workbook.getSheetAt(0);
161	            DataFormatter formatter = new DataFormatter();
162	            boolean headerSkipped = false;
163	            for (Row row : sheet) {
164	                if (!headerSkipped) {
165	                    headerSkipped = true;
166	                    continue;
167	                }
168	                int lastCell = row.getLastCellNum();
169	                if (lastCell <= 0) continue;
170	                String[] fields = new String[lastCell];
171	                for (int i = 0; i < lastCell; i++) {
172	                    Cell cell = row.getCell(i, Row.MissingCellPolicy.CREATE_NULL_AS_BLANK);
173	                    fields[i] = formatter.formatCellValue(cell);
174	                }
175	                if (fields.length > 0 && !fields[0].trim().isEmpty()) {
176	                    rows.add(fields);
177	                }
178	            }
179	        }
180	        return rows;
181	    }
