189	            effectiveFrom = LocalDate.now();
190	        }
191	
192	        MasterDataRequest request = MasterDataRequest.builder()
193	                .code(code)
194	                .name(name)
195	                .effectiveFrom(effectiveFrom)
196	                .build();
197	
198	        switch (entityType.toUpperCase()) {
199	            case "TERM":
200	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
201	                    request.setStartDate(parseDate(fields[3].trim(), "startDate"));
202	                }
203	                if (fields.length > 4 && !fields[4].trim().isEmpty()) {
204	                    request.setEndDate(parseDate(fields[4].trim(), "endDate"));
205	                }
206	                termService.create(request, userId);
207	                break;
208	            case "SCHOOL":
