210	                break;
211	            case "MAJOR":
212	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
213	                    request.setSchoolId(parseId(fields[3].trim(), "schoolId"));
214	                }
215	                majorService.create(request, userId);
216	                break;
217	            case "CLASS":
218	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
219	                    request.setMajorId(parseId(fields[3].trim(), "majorId"));
220	                }
221	                classService.create(request, userId);
222	                break;
223	            case "COURSE":
