242	        }
243	        try {
244	            return LocalDate.parse(value, DATE_FORMAT_US);
245	        } catch (DateTimeParseException e) {
246	            throw new IllegalArgumentException(
247	                    "Invalid date format for " + fieldName + ": '" + value + "' (expected yyyy-MM-dd or MM/dd/yyyy)");
