1	package com.campusfit.inbound.service;
2	
3	import com.campusfit.inbound.entity.InboundLine;
4	import com.campusfit.inbound.entity.PutawayTask;
5	import com.campusfit.inbound.repository.InboundLineRepository;
6	import com.campusfit.inbound.repository.PutawayTaskRepository;
7	import com.campusfit.shared.exception.BusinessException;
8	import com.campusfit.shared.exception.ResourceNotFoundException;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import java.time.LocalDateTime;
13	import java.util.ArrayList;
14	import java.util.List;
15	
16	@Service
17	public class PutawayService {
18	
19	    private final PutawayTaskRepository putawayTaskRepository;
20	    private final InboundLineRepository lineRepository;
21	
22	    public PutawayService(PutawayTaskRepository putawayTaskRepository,
23	                          InboundLineRepository lineRepository) {
24	        this.putawayTaskRepository = putawayTaskRepository;
25	        this.lineRepository = lineRepository;
26	    }
27	
28	    @Transactional
29	    public List<PutawayTask> generateTasks(Long receiptId) {
30	        List<InboundLine> lines = lineRepository.findByReceiptId(receiptId);
31	        List<PutawayTask> tasks = new ArrayList<>();
32	
33	        for (InboundLine line : lines) {
34	            if (line.getInspectionResult() == InboundLine.InspectionResult.PASS) {
35	                PutawayTask task = PutawayTask.builder()
36	                        .receiptId(receiptId)
37	                        .lineId(line.getId())
38	                        .suggestedLocation("ZONE-A-" + line.getItemCode())
39	                        .status(PutawayTask.TaskStatus.PENDING)
40	                        .build();
41	                tasks.add(task);
42	            }
43	        }
44	
45	        return putawayTaskRepository.saveAll(tasks);
46	    }
47	
48	    @Transactional
49	    public PutawayTask completeTask(Long receiptId, Long taskId, Long userId, String actualLocation) {
50	        PutawayTask task = putawayTaskRepository.findById(taskId)
51	                .orElseThrow(() -> new ResourceNotFoundException("PutawayTask", taskId));
52	
53	        if (!task.getReceiptId().equals(receiptId)) {
54	            throw new BusinessException("Task does not belong to the specified receipt");
55	        }
56	
57	        if (task.getStatus() != PutawayTask.TaskStatus.PENDING) {
58	            throw new BusinessException("Task is not in PENDING status");
59	        }
